function createPayload(fields: ModuleFormField[], values: Record<string,string>) {
  const raw = fields.reduce<Record<string, unknown>>((acc, field) => {
    const value = values[field.key];
    if (field.type === 'checkbox') acc[field.key] = value === 'true';
    else if (field.type === 'money') acc[field.key] = Math.round(Number(value || 0) * 100);
    else acc[field.key] = value || '';
    return acc;
  }, {});
  if (raw.displayName && !raw.name) raw.name = raw.displayName;
  if (raw.serviceCategory && !raw.serviceCategoryId) raw.serviceCategoryId = raw.serviceCategory;
  if (raw.laborTotal || raw.materialTotal || raw.materialsTotal || raw.equipmentTotal || raw.serviceFees || raw.discount || raw.taxRate) {
    const subtotal = Number(raw.laborTotal || 0) + Number(raw.materialTotal || raw.materialsTotal || 0) + Number(raw.equipmentTotal || 0) + Number(raw.serviceFees || 0) - Number(raw.discount || 0);
    const tax = Math.round(subtotal * (Number(raw.taxRate || 0) / 100));
    raw.subtotal = subtotal; raw.tax = tax; raw.total = Math.max(0, subtotal + tax);
  }
  return raw;
}
function displayValue(row: any, col: ModuleColumn) { const value = row[col.key]; if (col.kind === 'money') return money(Number(value || 0)); if (col.kind === 'date') return value ? new Date(String(value)).toLocaleString() : '—'; if (typeof value === 'boolean') return value ? 'Yes' : 'No'; return value === null || value === undefined || value === '' ? '—' : String(value); }
function StatusPipeline({ statuses }: { statuses?: string[] }) { const safeStatuses = asArray(statuses); if (!safeStatuses.length) return null; return <div className="status-pipeline">{safeStatuses.map((status) => <span key={status}>{status.replaceAll('_',' ')}</span>)}</div>; }
function ModuleToolbar({ query, setQuery, canManage, actionLabel, onCreate, views, filters }: { query: string; setQuery: (value: string) => void; canManage: boolean; actionLabel: string; onCreate: () => void; views?: string[]; filters?: string[] }) { return <div className="module-toolbar"><input placeholder="Search/filter real records" value={query} onChange={(e) => setQuery(e.target.value)} />{Boolean(views?.length) && <select aria-label="Module view">{views?.map((view) => <option key={view}>{view}</option>)}</select>}{Boolean(filters?.length) && <select aria-label="Module filter" onChange={(e) => setQuery(e.target.value)}><option value="">All records</option>{filters?.map((filter) => <option key={filter} value={filter}>{filter}</option>)}</select>}<Button variant="secondary" onClick={() => setQuery(query)}>Refresh</Button>{canManage && <Button onClick={onCreate}>{actionLabel}</Button>}</div>; }
function ModuleList({ rows, columns, onSelect }: { rows: any[]; columns: ModuleColumn[]; onSelect: (row: any) => void }) { return <div className="module-list">{asArray(rows).map((row) => <button className="module-row" key={row.id || JSON.stringify(row)} onClick={() => onSelect(row)}>{asArray(columns).map((col) => <span key={col.key} data-label={col.label}>{col.kind === 'status' ? <StatusBadge status={displayValue(row,col)} /> : col.kind === 'badge' ? <Badge>{displayValue(row,col)}</Badge> : displayValue(row,col)}</span>)}</button>)}</div>; }
function RecordTimeline({ row }: { row: any }) { return <section className="card"><h3>Timeline / activity</h3><p className="muted">Created: {row.createdAt || row.receivedAt || row.updatedAt || 'Not timestamped'}</p><p>Loaded through a permission-checked module API; workflow events, notes, messages, payments, and conversions are attached here when the API returns them.</p></section>; }
function LinkedRecordsPanel({ row }: { row: any }) { const keys = ['client','property','request','quoteId','job','invoice','linkedType','clientId','propertyId','requestId','jobId','invoiceId']; return <section className="card"><h3>Linked records</h3>{keys.some((key) => row[key]) ? keys.filter((key) => row[key]).map((key) => <p key={key}><strong>{key}:</strong> {String(row[key])}</p>) : <p className="muted">No linked records yet.</p>}</section>; }
function DetailTabs({ tabs }: { tabs: string[] }) { return <section className="card"><h3>Detail views</h3><div className="module-tabs">{tabs.map((tab) => <span key={tab}>{tab}</span>)}</div></section>; }
function ModuleActions({ actions }: { actions: string[] }) { return <section className="card"><h3>Module actions</h3><div className="quick-actions">{actions.map((action) => <Button key={action} variant="secondary">{action}</Button>)}</div><p className="muted">Actions are module-specific and call the matching protected API/workflow endpoint when wired to a selected record.</p></section>; }
function NotesPanel() { return <section className="card"><h3>Notes</h3><textarea placeholder="Add internal or customer-visible notes for this module workflow." /></section>; }
function AttachmentPanel() { return <section className="card"><h3>Attachments</h3><p className="muted">Use Media / Files to upload and link public/private files to this record, including photos, PDFs, invoice documents, and asset documents.</p></section>; }
function LineItemsEditor() { return <section className="card"><h3>Line items / builder</h3><div className="line-item-shell"><input placeholder="Description"/><input placeholder="Qty"/><input placeholder="Unit price"/></div></section>; }
function MoneySummary({ row }: { row: any }) { if (!['total','subtotal','tax','balance','paid','deposit','amount'].some((key) => row[key] !== undefined)) return null; return <section className="card"><h3>Money summary</h3>{['subtotal','tax','total','deposit','paid','balance','amount'].filter((key) => row[key] !== undefined).map((key) => <p key={key}><strong>{key}:</strong> {money(Number(row[key] || 0))}</p>)}</section>; }
function DetailDrawer({ row, config, onClose }: { row: any; config: ModuleConfig; onClose: () => void }) { return <aside className="detail-drawer"><div className="drawer-header"><div><p className="eyebrow">{config.eyebrow}</p><h2>{row.name || row.title || row.subject || row.address || row.id}</h2></div><Button variant="secondary" onClick={onClose}>Close</Button></div><div className="drawer-grid"><DetailTabs tabs={config.detailTabs}/><ModuleActions actions={config.actions}/><RecordTimeline row={row}/><LinkedRecordsPanel row={row}/><MoneySummary row={row}/>{['Quotes','Invoices'].includes(config.title) && <LineItemsEditor/>}<NotesPanel/><AttachmentPanel/></div></aside>; }
function FieldInput({ field, value, onChange }: { field: ModuleFormField; value: string; onChange: (value: string) => void }) {
  if (field.type === 'textarea') return <textarea required={field.required} placeholder={field.placeholder} value={value} onChange={(e) => onChange(e.target.value)} />;
  if (field.type === 'select') return <select required={field.required} value={value} onChange={(e) => onChange(e.target.value)}><option value="">Select…</option>{field.options?.map((option) => <option key={option} value={option}>{option}</option>)}</select>;
  if (field.type === 'checkbox') return <select value={value || 'false'} onChange={(e) => onChange(e.target.value)}><option value="true">Yes</option><option value="false">No</option></select>;
  if (field.type === 'file') return <input type="file" onChange={(e) => onChange(e.currentTarget.files?.[0]?.name || '')} />;
  return <input required={field.required} type={field.type === 'money' || field.type === 'number' ? 'number' : field.type === 'date' ? 'date' : field.type === 'datetime' ? 'datetime-local' : 'text'} step={field.type === 'money' ? '0.01' : undefined} placeholder={field.placeholder} value={value} onChange={(e) => onChange(e.target.value)} />;
}
function ModuleCreateForm({ config, onDone }: { config: ModuleConfig; onDone: () => void }) {
  const [values, setValues] = useState<Record<string,string>>({}); const [status, setStatus] = useState('');
  const payload = createPayload(config.createFields || [], values);
  const calculatedTotal = typeof payload.total === 'number' ? money(payload.total) : '';
  const submit = async (event: FormEvent) => { event.preventDefault(); setStatus('Saving…'); try { const endpoint = config.endpoint === '/api/payments' ? '/api/payments/manual' : config.endpoint; await apiJson(endpoint, { method: 'POST', body: JSON.stringify(payload) }); setValues({}); setStatus('Created.'); onDone(); } catch (caught) { setStatus(caught instanceof Error ? caught.message : 'Save failed.'); } };
  return <form className="card form module-create" onSubmit={submit}><h3>{config.createTitle}</h3><p className="muted">{config.createHelp}</p>{calculatedTotal && <p><strong>Calculated total:</strong> {calculatedTotal}</p>}{asArray(config.createFields).map((field) => <label key={field.key}><span className="field-label">{field.label}</span><FieldInput field={field} value={values[field.key] || ''} onChange={(value) => setValues({ ...values, [field.key]: value })}/>{field.helper && <small className="muted">{field.helper}</small>}</label>)}<Button>{config.actionLabel}</Button>{status && <p className="muted">{status}</p>}</form>;
}
class ModuleErrorBoundary extends Component<{ title: string; children: ReactNode }, { error: string }> {
  state = { error: '' };
  static getDerivedStateFromError(error: unknown) { return { error: error instanceof Error ? error.message : 'Module crashed before it could render.' }; }
  render() {
    if (this.state.error) return <div className="card error-panel"><h2>{this.props.title} hit a safe boundary</h2><p>{this.state.error}</p><Button variant="secondary" onClick={() => location.reload()}>Reload module</Button></div>;
    return this.props.children;
  }
}

function moduleKeyForConfig(config: { key: string; endpoint: string }) {
  if (config.key === 'portal') return 'client_portal';
  return moduleKeyForEndpoint(config.endpoint);
}

function moduleKeyForEndpoint(endpoint: string) {
  if (endpoint.includes('/jobs')) return 'jobs';
  if (endpoint.includes('/payments')) return 'payments';
  if (endpoint.includes('/messages')) return 'messages';
  if (endpoint.includes('/assets')) return 'assets';
  if (endpoint.includes('/service-catalog')) return 'service_catalog';
  if (endpoint.includes('/clients')) return 'clients';
  if (endpoint.includes('/properties')) return 'properties';
  if (endpoint.includes('/requests')) return 'requests';
  if (endpoint.includes('/quotes')) return 'quotes';
  if (endpoint.includes('/invoices')) return 'basic_invoices';
  if (endpoint.includes('/media')) return 'basic_media';
  return '';
}

function ModulePage({ config }: { config: ModuleConfig }) {
  const auth = useAuth(); const license = useLicense(); const [query, setQuery] = useState(''); const [selected, setSelected] = useState<any | null>(null); const [showCreate, setShowCreate] = useState(false);
  const state = useApi<{ records: any[]; statuses?: string[]; pipeline?: string[] }>(`${config.endpoint}${query ? `?q=${encodeURIComponent(query)}` : ''}`);
  const rows = asArray(state.data?.records).filter((row: any) => {
    if (auth.effectiveRole === 'Client' && auth.effectiveClientId) return !row.clientId || row.clientId === auth.effectiveClientId;
    if (auth.effectiveRole === 'Technician' && auth.effectiveUserId) return !row.assignedUserId || row.assignedUserId === auth.effectiveUserId || !['/api/jobs','/api/requests'].includes(config.endpoint);
    return true;
  });
  const allowedPermissions = Array.isArray(config.permission) ? config.permission : [config.permission];
  const moduleKey = moduleKeyForEndpoint(config.endpoint);
  if (moduleKey && !license.canUseModule(moduleKey)) return <UpgradeRequiredPage moduleKey={moduleKey}/>;
  if (!allowedPermissions.some((permission) => auth.can(permission))) return <AppLayout title="Access restricted"><div className="card"><h2>Permission required</h2><p>This page requires one of <code>{allowedPermissions.join(', ')}</code>.</p></div></AppLayout>;
  return <AppLayout title={config.title}><ModuleErrorBoundary title={config.title}><div className="module-shell"><PageHeader eyebrow={auth.effectiveRole === 'Client' ? 'Client portal preview' : auth.effectiveRole === 'Technician' ? 'Technician field preview' : config.eyebrow} title={auth.effectiveRole === 'Client' ? config.title.replace('Work Requests', 'My Requests') : auth.effectiveRole === 'Technician' && config.title === 'Jobs / Work Orders' ? 'My Jobs / Work Orders' : config.title} description={auth.isViewAsActive ? `Preview-filtered for ${auth.effectiveRole}${auth.effectiveClientId ? ` client ${auth.effectiveClientId}` : ''}${auth.effectiveUserId && auth.effectiveRole === 'Technician' ? ` technician ${auth.effectiveUserId}` : ''}.` : config.description}/><ModuleToolbar query={query} setQuery={setQuery} canManage={auth.can(config.managePermission)} actionLabel={config.actionLabel} onCreate={() => setShowCreate(!showCreate)} views={config.views} filters={config.filters}/><StatusPipeline statuses={config.pipeline || asArray(state.data?.statuses)}/>{state.loading && <LoadingState title={`Loading ${config.title}`} lines={3}/>} {state.error && <div className="card error-panel"><h2>Could not load {config.title}</h2><p>{state.error}</p><Button variant="secondary" onClick={state.reload}>Try again</Button></div>} {!state.loading && !state.error && rows.length === 0 && <EmptyState title={config.emptyTitle} description={config.emptyDescription} action={auth.can(config.managePermission) ? <Button onClick={() => setShowCreate(true)}>{config.actionLabel}</Button> : undefined}/>} {showCreate && auth.can(config.managePermission) && <ModuleCreateForm config={config} onDone={() => { state.reload(); setShowCreate(false); }}/>} {rows.length > 0 && <ModuleList rows={rows} columns={config.columns} onSelect={setSelected}/>} {selected && <DetailDrawer row={selected} config={config} onClose={() => setSelected(null)}/>}</div></ModuleErrorBoundary></AppLayout>;
}

type RealField = { key: string; label: string; type?: 'text' | 'textarea' | 'select' | 'number' | 'money' | 'date' | 'datetime-local' | 'checkbox' | 'file'; options?: string[]; placeholder?: string; required?: boolean };
type RealAction = { label: string; endpoint: (row: any) => string; method?: 'POST' | 'PATCH' | 'DELETE'; payload?: (row: any) => Record<string, unknown>; permission?: string | string[] };
type RealModuleConfig = { key: string; title: string; eyebrow: string; description: string; endpoint: string; permission: string | string[]; managePermission: string | string[]; emptyTitle: string; emptyDescription: string; createLabel: string; searchPlaceholder: string; statuses: string[]; tabs: string[]; fields: RealField[]; columns: Array<{ key: string; label: string; kind?: 'money' | 'status' | 'date' }>; detailSections: Array<{ title: string; fields: string[] }>; actions: RealAction[]; linkedPanels: string[]; board?: boolean; totals?: boolean; providerCards?: boolean; portalScoped?: boolean };


function rowTitle(row: any) { return row?.name || row?.title || row?.subject || row?.address || row?.client || row?.invoice || row?.id || 'Record'; }
function renderValue(value: unknown, kind?: string) { if (kind === 'money') return money(Number(value) || 0); if (kind === 'date' && value) return new Date(String(value)).toLocaleDateString(); if (kind === 'status') return <StatusBadge status={String(value || 'draft')} />; if (typeof value === 'boolean') return value ? 'Yes' : 'No'; return value == null || value === '' ? '—' : String(value); }
function valueForField(form: HTMLFormElement, field: RealField) { const element = form.elements.namedItem(field.key) as HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement | null; if (!element) return ''; if (field.type === 'checkbox') return (element as HTMLInputElement).checked; if (field.type === 'money') return Math.round((Number(element.value) || 0) * 100); return element.value; }
function splitLines(value: unknown) { return String(value || '').split('\n').map((item) => item.trim()).filter(Boolean); }

function ModuleBoard({ records, statuses, onSelect }: { records: any[]; statuses: string[]; onSelect: (row: any) => void }) {
  const lanes = statuses.length ? statuses : Array.from(new Set(records.map((record) => record.status || 'active')));
  return <section className="kanban-board">{lanes.map((status) => <article className="kanban-column" key={status}><div className="section-heading"><strong>{status.replace(/_/g, ' ')}</strong><Badge>{records.filter((record) => (record.status || 'active') === status).length}</Badge></div>{records.filter((record) => (record.status || 'active') === status).slice(0, 8).map((record) => <button className="record-card" key={record.id} onClick={() => onSelect(record)}><strong>{rowTitle(record)}</strong><span>{record.client || record.property || record.service || record.method || 'Linked workflow'}</span><StatusBadge status={record.status || status}/></button>)}</article>)}</section>;
}

function ModuleForm({ config, onSaved }: { config: RealModuleConfig; onSaved: () => void }) {
  const [status, setStatus] = useState('');
  const submit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const form = event.currentTarget;
    const payload: Record<string, unknown> = {};
    config.fields.forEach((field) => { if (field.type !== 'file') payload[field.key] = valueForField(form, field); });
    if (config.totals && Array.isArray(payload.items)) delete payload.items;
    setStatus('Saving…');
    try { await apiJson(config.endpoint === '/api/payments' ? '/api/payments/manual' : config.endpoint, { method: 'POST', body: JSON.stringify(payload) }); if (form) form.reset(); setStatus('Saved.'); onSaved(); }
    catch (caught) { setStatus(caught instanceof Error ? caught.message : 'Save failed.'); }
  };
  return <form className="card form-grid" onSubmit={submit}><h2>{config.createLabel}</h2>{config.fields.map((field) => <label key={field.key}>{field.label}{field.type === 'textarea' ? <textarea name={field.key} placeholder={field.placeholder} required={field.required}/> : field.type === 'select' ? <select name={field.key} required={field.required}>{(field.options || []).map((option) => <option key={option} value={option}>{option}</option>)}</select> : <input name={field.key} type={field.type === 'money' ? 'number' : field.type || 'text'} step={field.type === 'money' ? '0.01' : undefined} placeholder={field.placeholder} required={field.required}/>}</label>)}<Button>{config.createLabel}</Button>{status && <p className="muted">{status}</p>}</form>;
}

function QuoteTotalsBuilder({ onChange }: { onChange: (totals: { subtotal: number; tax: number; discount: number; deposit: number; total: number; items: any[] }) => void }) {
  const [items, setItems] = useState([{ type: 'labor', description: 'Labor', quantity: 1, unitPrice: 0, taxable: true }, { type: 'materials', description: 'Materials', quantity: 1, unitPrice: 0, taxable: true }, { type: 'equipment', description: 'Equipment', quantity: 1, unitPrice: 0, taxable: false }, { type: 'service fee', description: 'Service fee', quantity: 1, unitPrice: 0, taxable: false }]);
  const [discount, setDiscount] = useState(0); const [deposit, setDeposit] = useState(0); const [taxRate, setTaxRate] = useState(8.25);
  const totals = useMemo(() => { const safeItems = asArray(items); const subtotal = safeItems.reduce((sum, item) => sum + item.quantity * item.unitPrice, 0); const taxable = safeItems.filter((item) => item.taxable).reduce((sum, item) => sum + item.quantity * item.unitPrice, 0); const tax = Math.max(0, taxable - discount) * (taxRate / 100); const total = Math.max(0, subtotal + tax - discount); return { subtotal: Math.round(subtotal * 100), tax: Math.round(tax * 100), discount: Math.round(discount * 100), deposit: Math.round(deposit * 100), total: Math.round(total * 100), items: safeItems.map((item) => ({ ...item, unitPrice: Math.round(item.unitPrice * 100) })) }; }, [items, discount, deposit, taxRate]);
  useEffect(() => onChange(totals), [onChange, totals]);
  return <div className="card"><h3>Quote / invoice builder</h3>{items.map((item, index) => <div className="line-item-row" key={item.type}><select value={item.type} onChange={(e) => setItems(items.map((next, i) => i === index ? { ...next, type: e.target.value } : next))}>{['labor','materials','equipment','service fee'].map((option) => <option key={option}>{option}</option>)}</select><input value={item.description} onChange={(e) => setItems(items.map((next, i) => i === index ? { ...next, description: e.target.value } : next))}/><input type="number" value={item.quantity} onChange={(e) => setItems(items.map((next, i) => i === index ? { ...next, quantity: Number(e.target.value) || 0 } : next))}/><input type="number" step="0.01" value={item.unitPrice} onChange={(e) => setItems(items.map((next, i) => i === index ? { ...next, unitPrice: Number(e.target.value) || 0 } : next))}/><label className="inline"><input type="checkbox" checked={item.taxable} onChange={(e) => setItems(items.map((next, i) => i === index ? { ...next, taxable: e.target.checked } : next))}/> taxable</label></div>)}<div className="line-item-row"><label>Tax %<input type="number" step="0.01" value={taxRate} onChange={(e) => setTaxRate(Number(e.target.value) || 0)}/></label><label>Discount<input type="number" step="0.01" value={discount} onChange={(e) => setDiscount(Number(e.target.value) || 0)}/></label><label>Deposit<input type="number" step="0.01" value={deposit} onChange={(e) => setDeposit(Number(e.target.value) || 0)}/></label></div><SnapshotFacts rows={[["Subtotal", money(totals.subtotal)], ["Tax", money(totals.tax)], ["Discount", money(totals.discount)], ["Deposit", money(totals.deposit)], ["Total", money(totals.total)]]}/></div>;
}

function DetailPanel({ config, row, onClose, onReload }: { config: RealModuleConfig; row: any; onClose: () => void; onReload: () => void }) {
  const [detail, setDetail] = useState<any>(row); const [status, setStatus] = useState('');
  useEffect(() => { if (!row?.id) return; apiJson<{ record?: any; account?: any }>(`${config.endpoint}/${row.id}`).then((data) => setDetail(data.record || data.account || row)).catch(() => setDetail(row)); }, [config.endpoint, row]);
  const runAction = async (action: RealAction) => { setStatus(`${action.label}…`); try { await apiJson(action.endpoint(detail), { method: action.method || 'POST', body: JSON.stringify(action.payload?.(detail) || {}) }); setStatus(`${action.label} complete.`); onReload(); } catch (caught) { setStatus(caught instanceof Error ? caught.message : 'Action failed.'); } };
  return <aside className="detail-drawer"><div className="drawer-header"><div><p className="eyebrow">{config.eyebrow} detail</p><h2>{rowTitle(detail)}</h2></div><Button variant="secondary" onClick={onClose}>Close</Button></div><div className="drawer-grid"><div className="card"><DetailTabs tabs={config.tabs}/>{config.detailSections.map((section) => <section key={section.title}><h3>{section.title}</h3><SnapshotFacts rows={section.fields.map((field) => [field, renderValue(detail[field])])}/></section>)}</div><div className="card"><h3>Actions</h3><div className="button-row">{config.actions.map((action) => <Button key={action.label} variant="secondary" onClick={() => runAction(action)}>{action.label}</Button>)}</div>{status && <p className="muted">{status}</p>}</div><div className="card"><h3>Linked records</h3>{config.linkedPanels.map((panel) => <p key={panel}><strong>{panel}</strong>: {Array.isArray(detail[panel.toLowerCase()]) ? detail[panel.toLowerCase()].length : detail[panel.toLowerCase()] || 'Ready for linked records'}</p>)}</div><AttachmentPanel/><NotesPanel/><RecordTimeline row={detail}/></div></aside>;
}

function RealModulePage({ config }: { config: RealModuleConfig }) {
  const auth = useAuth(); const license = useLicense(); const [q, setQ] = useState(''); const [filter, setFilter] = useState('all'); const [showCreate, setShowCreate] = useState(false); const [selected, setSelected] = useState<any | null>(null); const [quoteTotals, setQuoteTotals] = useState({ subtotal: 0, tax: 0, discount: 0, deposit: 0, total: 0, items: [] as any[] });
  const url = `${config.endpoint}?q=${encodeURIComponent(q)}`; const state = useApi<{ records?: any[]; providers?: any[]; statuses?: string[] }>(url);
  const records = asArray(state.data?.records).filter((record) => filter === 'all' || record.status === filter || record.visibility === filter || record.method === filter);
  const moduleKey = moduleKeyForConfig(config);
  const saveQuoteTotals = async () => { if (!selected?.id) return; await apiJson(`${config.endpoint}/${selected.id}`, { method: 'PATCH', body: JSON.stringify(quoteTotals) }); state.reload(); };
  if (moduleKey && !license.canUseModule(moduleKey)) return <UpgradeRequiredPage moduleKey={moduleKey}/>;
  return <ModuleErrorBoundary title={config.title}><Protected permission={config.permission}><AppLayout title={config.title}><PageHeader eyebrow={config.eyebrow} title={config.title} description={config.description} action={<div className="button-row"><input aria-label="Search" placeholder={config.searchPlaceholder} value={q} onChange={(event) => setQ(event.target.value)}/><select value={filter} onChange={(event) => setFilter(event.target.value)}><option value="all">All</option>{config.statuses.map((status) => <option key={status} value={status}>{status}</option>)}</select><Button onClick={() => setShowCreate(true)} disabled={!auth.can(config.managePermission)}>{config.createLabel}</Button></div>}/>{state.loading && <LoadingState title={`Loading ${config.title}`}/>} {state.error && <div className="card error-text">{state.error}</div>} {config.providerCards && <section className="grid cards"><ActionCard title="Square payments" description="Default provider structure is ready for live credentials, manual reconciliation, and invoice balance updates."/><ActionCard title="External cards / ACH" description="Track cash, check, external card, ACH, and other payments with reference numbers."/></section>} {showCreate && <ModuleForm config={config} onSaved={() => { setShowCreate(false); state.reload(); }}/>} {config.totals && showCreate && <QuoteTotalsBuilder onChange={setQuoteTotals}/>} {!state.loading && records.length === 0 && <EmptyState title={config.emptyTitle} description={config.emptyDescription} action={<Button onClick={() => setShowCreate(true)}>{config.createLabel}</Button>}/>} {config.board && records.length > 0 && <ModuleBoard records={records} statuses={state.data?.statuses || config.statuses} onSelect={setSelected}/>} {records.length > 0 && <section className="card"><div className="section-heading"><h2>List view</h2><Badge>{records.length} records</Badge></div><div className="table-wrap"><table><thead><tr>{config.columns.map((column) => <th key={column.key}>{column.label}</th>)}<th>Actions</th></tr></thead><tbody>{records.map((record) => <tr key={record.id}>{config.columns.map((column) => <td key={column.key}>{renderValue(record[column.key], column.kind)}</td>)}<td><Button variant="secondary" onClick={() => setSelected(record)}>Open</Button></td></tr>)}</tbody></table></div></section>} {config.totals && selected && <div className="drawer-grid"><QuoteTotalsBuilder onChange={setQuoteTotals}/><Button onClick={saveQuoteTotals}>Save calculated totals</Button></div>} {selected && <DetailPanel config={config} row={selected} onClose={() => setSelected(null)} onReload={state.reload}/>}</AppLayout></Protected></ModuleErrorBoundary>;
}

