realModules.assets = simpleModule('assets', { title: 'Assets / CMMS', eyebrow: 'Equipment', endpoint: '/api/assets', permission: 'cmms.view', managePermission: 'cmms.manage', description: 'Asset tracking with property/client link, manufacturer, model, serial, install date, warranty, condition, service history, linked jobs, photos/docs, and notes.', createLabel: 'Create Asset', fields: [{key:'propertyId',label:'Property ID'},{key:'name',label:'Asset name',required:true},{key:'type',label:'Asset type'},{key:'manufacturer',label:'Manufacturer'},{key:'model',label:'Model'},{key:'serial',label:'Serial number'},{key:'installedAt',label:'Install date',type:'date'},{key:'status',label:'Condition / status',type:'select',options:['active','needs_service','offline','retired']},{key:'notes',label:'Notes',type:'textarea'}], columns: [{key:'name',label:'Asset'},{key:'status',label:'Status',kind:'status'},{key:'type',label:'Type'},{key:'manufacturer',label:'Manufacturer'},{key:'model',label:'Model'},{key:'serial',label:'Serial'},{key:'property',label:'Property'}] });
realModules['service-catalog'] = simpleModule('service-catalog', { title: 'Service Catalog', eyebrow: 'Services', endpoint: '/api/service-catalog', permission: 'service_catalog.view', managePermission: 'service_catalog.manage', description: 'Categories and services used by public Request Estimate and Quote builder, with visibility, default labor, checklists, and quote template text.', createLabel: 'Create Service', fields: [{key:'name',label:'Service/category',required:true},{key:'description',label:'Description',type:'textarea'},{key:'enabled',label:'Enabled',type:'checkbox'},{key:'publicVisibility',label:'Public visibility',type:'checkbox'},{key:'defaultLaborHours',label:'Default labor hours',type:'number'},{key:'defaultLaborRate',label:'Default labor rate',type:'money'},{key:'defaultChecklist',label:'Default checklist',type:'textarea'},{key:'quoteTemplateText',label:'Quote template text',type:'textarea'}], columns: [{key:'name',label:'Service'},{key:'enabled',label:'Enabled'},{key:'description',label:'Description'},{key:'defaultLaborRate',label:'Labor rate',kind:'money'}] });
